def score_pct(self) -> float:
    if self.total == 0:
        return 100.0
    return round(self.score_pass / self.total * 100, 1)

def _find_registry(config: CartographerConfig, base_dir: Path) -> Path | None:
    if config.stack.arbiter_registry:
        p = Path(config.stack.arbiter_registry)
        return p if p.is_absolute() and p.exists() else (base_dir / p if (base_dir / p).exists() else None)
    for name in [".arbiter/registry", ".arbiter"]:
        candidate = base_dir / name
        if candidate.exists():
            return candidate
    return None

def _find_baton_config(config: CartographerConfig, base_dir: Path) -> Path | None:
    if config.stack.baton_config:
        p = Path(config.stack.baton_config)
        return p if p.exists() else base_dir / p
    for name in ["baton.yaml", "baton.yml"]:
        candidate = base_dir / name
        if candidate.exists():
            return candidate
    return None

def _version_lt(a: str, b: str) -> bool:
    """Simple version comparison."""
    try:
        a_parts = [int(x) for x in a.split(".")]
        b_parts = [int(x) for x in b.split(".")]
        return a_parts < b_parts
    except ValueError:
        return a < b

def _find_registry(config: CartographerConfig, base_dir: Path) -> Path | None:
    if config.stack.ledger_registry:
        p = Path(config.stack.ledger_registry)
        return p if p.is_absolute() and p.exists() else (base_dir / p if (base_dir / p).exists() else None)
    for name in [".ledger/registry", ".ledger"]:
        candidate = base_dir / name
        if candidate.exists():
            return candidate
    return None

def check(self, config: CartographerConfig, base_dir: Path) -> list[CheckResult]:
    results: list[CheckResult] = []

    registry_path = _find_registry(config, base_dir)
    if registry_path is None:
        results.append(CheckResult(
            check_id="ledger_registry_exists",
            target=".ledger/registry/",
            severity=Severity.INFO,
            status="INFO",
            message="no ledger registry found",
            tool="ledger",
        ))
        return results

    # Load all schema files
    schemas: list[tuple[Path, dict]] = []
    for f in sorted(registry_path.rglob("*.yaml")):
        try:
            with open(f) as fh:
                data = yaml.safe_load(fh)
            if isinstance(data, dict):
                schemas.append((f, data))
        except Exception:
            pass

    for schema_path, schema in schemas:
        fields = schema.get("fields", [])
        if not isinstance(fields, list):
            continue

        missing_classification = 0
        for field in fields:
            if isinstance(field, dict) and "classification" not in field:
                missing_classification += 1

        if missing_classification == 0:
            results.append(CheckResult(
                check_id="all_fields_have_classification",
                target=str(schema_path),
                severity=Severity.FAIL,
                status="PASS",
                message="all fields have classification",
                tool="ledger",
            ))
        else:
            results.append(CheckResult(
                check_id="all_fields_have_classification",
                target=str(schema_path),
                severity=Severity.FAIL if missing_classification > len(fields) // 2 else Severity.WARN,
                status="FAIL" if missing_classification > len(fields) // 2 else "WARN",
                message=f"{missing_classification} fields missing classification",
                tool="ledger",
            ))

        # Check annotation conflicts
        annotations = {}
        for field in fields:
            if not isinstance(field, dict):
                continue
            name = field.get("name", "")
            anns = field.get("annotations", [])
            if isinstance(anns, list):
                if "gdpr_erasable" in anns and "immutable" in anns:
                    results.append(CheckResult(
                        check_id="no_annotation_conflicts",
                        target=f"{schema_path}:{name}",
                        severity=Severity.FAIL,
                        status="FAIL",
                        message="field is both gdpr_erasable and immutable",
                        tool="ledger",
                    ))

        # GDPR erasure check
        for field in fields:
            if not isinstance(field, dict):
                continue
            anns = field.get("annotations", [])
            if isinstance(anns, list) and "gdpr_erasable" in anns:
                if "erasure_method" not in field:
                    results.append(CheckResult(
                        check_id="gdpr_erasable_has_erasure_method",
                        target=f"{schema_path}:{field.get('name', '')}",
                        severity=Severity.WARN,
                        status="WARN",
                        message="gdpr_erasable field has no erasure_method",
                        tool="ledger",
                    ))

        # Audit retention check
        for field in fields:
            if not isinstance(field, dict):
                continue
            anns = field.get("annotations", [])
            if isinstance(anns, list) and "audit_field" in anns:
                if "retention_policy" not in field:
                    results.append(CheckResult(
                        check_id="audit_fields_have_retention_policy",
                        target=f"{schema_path}:{field.get('name', '')}",
                        severity=Severity.WARN,
                        status="WARN",
                        message="audit field has no retention_policy",
                        tool="ledger",
                    ))

    return results

def check(self, config: CartographerConfig, base_dir: Path) -> list[CheckResult]:
    results: list[CheckResult] = []
    pact_dir = config.stack.pact_project_dir
    if pact_dir is None:
        # Try common locations
        for candidate in [".pact", "contracts", "pact"]:
            if (base_dir / candidate).exists():
                pact_dir = str(base_dir / candidate)
                break

    # Check contracts
    if pact_dir:
        pact_path = Path(pact_dir)
        if pact_path.is_absolute():
            contract_dir = pact_path
        else:
            contract_dir = base_dir / pact_path
        results.extend(self._check_contracts(contract_dir))

    # Check source files for PACT keys and handlers
    pact_key_re = re.compile(config.compatibility.pact_key_format)
    results.extend(self._check_source(config, base_dir, pact_key_re))

    return results

def _check_source(
    self,
    config: CartographerConfig,
    base_dir: Path,
    pact_key_re: re.Pattern,
) -> list[CheckResult]:
    results: list[CheckResult] = []
    source_dirs = config.targets.source.dirs
    exclude = config.targets.source.exclude

    py_files: list[Path] = []
    for d in source_dirs:
        src = base_dir / d
        if not src.exists():
            continue
        for f in src.rglob("*.py"):
            if any(part in exclude for part in f.parts):
                continue
            py_files.append(f)

    for f in py_files:
        try:
            content = f.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue

        # source_has_pact_key
        keys = pact_key_re.findall(content)
        if not keys:
            # Only flag if this looks like a substantive module
            if "class " in content or "def " in content:
                results.append(CheckResult(
                    check_id="source_has_pact_key",
                    target=str(f),
                    severity=Severity.FAIL,
                    status="FAIL",
                    message="no PACT key found in any method",
                    tool="pact",
                ))
        else:
            # Validate key format
            for key in keys:
                if not pact_key_re.fullmatch(key):
                    results.append(CheckResult(
                        check_id="pact_key_format_valid",
                        target=str(f),
                        severity=Severity.FAIL,
                        status="FAIL",
                        message=f"malformed PACT key: {key}",
                        tool="pact",
                    ))

        # source_has_event_handler
        if "class " in content:
            if "event_handler" not in content:
                results.append(CheckResult(
                    check_id="source_has_event_handler",
                    target=str(f),
                    severity=Severity.FAIL,
                    status="FAIL",
                    message="no event_handler parameter",
                    tool="pact",
                ))
            elif "log_handler" not in content:
                results.append(CheckResult(
                    check_id="source_has_log_handler",
                    target=str(f),
                    severity=Severity.WARN,
                    status="WARN",
                    message="event_handler present but log_handler missing",
                    tool="pact",
                ))

    return results

def run_checks(
    config: CartographerConfig,
    base_dir: Path,
    tools: list[str] | None = None,
) -> list[CheckResult]:
    """Run compatibility checks for the specified tools (or all)."""
    results: list[CheckResult] = []

    for checker_cls in ALL_CHECKERS:
        checker = checker_cls()
        if tools and checker.tool_name not in tools:
            continue
        results.extend(checker.check(config, base_dir))

    return results

