    if config.stack.sentinel_manifest:
        p = Path(config.stack.sentinel_manifest)
        return p if p.is_absolute() and p.exists() else (base_dir / p if (base_dir / p).exists() else None)
    for name in [".sentinel/manifest.json", "sentinel_manifest.json"]:
        candidate = base_dir / name
        if candidate.exists():
            return candidate
    return None

def load_config(path: Path | None = None) -> CartographerConfig:
    """Load configuration from a YAML file, or return defaults."""
    if path is None:
        path = find_config()
    if path is None or not path.exists():
        return CartographerConfig()
    with open(path) as f:
        raw: dict[str, Any] = yaml.safe_load(f) or {}
    return CartographerConfig(**raw)

def _match_backend(name: str) -> str | None:
    for pattern, backend in BACKEND_ENV_PATTERNS.items():
        if re.match(pattern, name, re.IGNORECASE):
            return backend
    return None

def scan(self, file_path: Path, content: str) -> list[DiscoveredEnvVar]:
    results: list[DiscoveredEnvVar] = []
    seen: set[str] = set()

    for i, line in enumerate(content.split("\n"), 1):
        for match in ENV_ACCESS_RE.finditer(line):
            # Extract the matched group (whichever alternative matched)
            name = next(g for g in match.groups() if g is not None)
            if name in seen:
                continue
            seen.add(name)

            backend_hint = _match_backend(name)
            if backend_hint:
                results.append(
                    DiscoveredEnvVar(
                        name=name,
                        source_file=str(file_path),
                        line=i,
                        backend_hint=backend_hint,
                        confidence=Confidence.MEDIUM,
                    )
                )

    return results

def scan(self, file_path: Path, content: str) -> list[DiscoveredPactKey]:
    results: list[DiscoveredPactKey] = []
    for i, line in enumerate(content.split("\n"), 1):
        for match in self._re.finditer(line):
            results.append(
                DiscoveredPactKey(
                    key=match.group(0),
                    source_file=str(file_path),
                    line=i,
                    confidence=Confidence.HIGH,
                )
            )
    return results

def _collect_files(
    dirs: list[str],
    extensions: list[str],
    exclude: list[str],
    base: Path,
) -> list[Path]:
    """Collect all files matching extensions under the given directories."""
    files: list[Path] = []
    for d in dirs:
        root = base / d
        if not root.exists():
            continue
        for ext in extensions:
            for f in root.rglob(f"*{ext}"):
                if any(part in exclude for part in f.parts):
                    continue
                files.append(f)
    return sorted(files)

def load_patterns(custom_path: Path | None = None) -> dict[str, list[str]]:
    """Load classification patterns, merging custom patterns if provided."""
    patterns = dict(DEFAULT_PATTERNS)
    if custom_path and custom_path.exists():
        with open(custom_path) as f:
            custom: dict[str, list[str]] = yaml.safe_load(f) or {}
        for tier, fields in custom.items():
            if tier in patterns:
                existing = set(patterns[tier])
                patterns[tier].extend(f for f in fields if f not in existing)
            else:
                patterns[tier] = fields
    return patterns

def _extract_identifiers(line: str) -> list[str]:
    """Extract identifier-like tokens from a line of code."""
    import re

    # Match word characters, including underscores (common in field names)
    return re.findall(r"\b[a-zA-Z_][a-zA-Z0-9_]*\b", line)

def __init__(self, custom_patterns_path: Path | None = None):
    self._patterns = load_patterns(custom_patterns_path)
    # Build a lookup: field_name -> (tier, pattern)
    self._lookup: dict[str, tuple[str, str]] = {}
    for tier, field_names in self._patterns.items():
        for name in field_names:
            self._lookup[name.lower()] = (tier, name)

def _extract_go_fields(struct_body: str) -> list[DiscoveredField]:
    fields: list[DiscoveredField] = []
    for line in struct_body.strip().split("\n"):
        line = line.strip()
        if not line or line.startswith("//"):
            continue
        parts = line.split()
        if len(parts) >= 2 and parts[0][0].isupper():
            fields.append(
                DiscoveredField(
                    name=parts[0],
                    type=parts[1],
                    confidence=Confidence.HIGH,
                )
            )
    return fields

def _scan_structs(
    self, file_path: Path, content: str, result: DiscoveryResult
) -> None:
