def report(ctx: click.Context) -> None:
    """Show the most recent compatibility report."""
    base_dir: Path = ctx.obj["base_dir"]
    report_dir = base_dir / ".cartographer" / "reports"

    for name in ["report_latest.txt", "report_latest.json"]:
        path = report_dir / name
        if path.exists():
            click.echo(path.read_text())
            return

    click.echo("No reports found. Run 'cartographer check' first.")

def drafts_list(ctx: click.Context, tool_name: str | None) -> None:
    """List all draft artifacts."""
    config: CartographerConfig = ctx.obj["config"]
    base_dir: Path = ctx.obj["base_dir"]
    output_dir = base_dir / config.output_dir

    if not output_dir.exists():
        click.echo("No drafts found.")
        return

    for f in sorted(output_dir.rglob("*")):
        if f.is_file():
            rel = f.relative_to(output_dir)
            tool = rel.parts[0] if len(rel.parts) > 1 else "unknown"
            if tool_name and tool != tool_name:
                continue
            click.echo(f"  {rel}")

def _infer_tool(path: Path, output_dir: Path) -> str:
    """Infer the target tool from the artifact path."""
    try:
        rel = path.relative_to(output_dir)
        return rel.parts[0] if len(rel.parts) > 1 else "unknown"
    except ValueError:
        return "unknown"

def _has_classification_fields(data: dict) -> bool:
    """Check if the artifact contains classification fields."""
    if "classification" in data or "_classification_confidence" in data:
        return True
    for v in data.values():
        if isinstance(v, dict) and _has_classification_fields(v):
            return True
        if isinstance(v, list):
            for item in v:
                if isinstance(item, dict) and _has_classification_fields(item):
                    return True
    return False

def format_text(report: CompatibilityReport) -> str:
    """Format report as human-readable text."""
    lines = [
        "CARTOGRAPHER COMPATIBILITY REPORT",
        f"generated: {report.generated}",
        "",
    ]

    # Group by tool
    by_tool: dict[str, list[CheckResult]] = {}
    for check in report.checks:
        by_tool.setdefault(check.tool.upper(), []).append(check)

    for tool, checks in sorted(by_tool.items()):
        lines.append(f"{tool} COMPATIBILITY")
        for check in checks:
            status = check.status.ljust(6)
            target = check.target
            # Truncate long paths
            if len(target) > 40:
                target = "..." + target[-37:]
            lines.append(f"  {target:<42} {status} {check.message}")
        lines.append("")

    # Overall score
    lines.append(
        f"OVERALL SCORE: {report.score_pct}% compliant "
        f"({report.score_pass}/{report.total} checks passing)"
    )
    lines.append(
        f"  FAIL: {report.score_fail}   WARN: {report.score_warn}   PASS: {report.score_pass}"
    )
    lines.append("")

    if report.recommendations:
        lines.append("RECOMMENDED NEXT STEPS (in order):")
        for i, rec in enumerate(report.recommendations, 1):
            lines.append(f"  {i}. {rec}")

    return "\n".join(lines)

def format_json(report: CompatibilityReport) -> str:
    """Format report as JSON."""
    data = {
        "generated": report.generated,
        "score": {
            "pass": report.score_pass,
            "warn": report.score_warn,
            "fail": report.score_fail,
            "total": report.total,
            "percent": report.score_pct,
        },
        "checks": [
            {
                "check_id": c.check_id,
                "target": c.target,
                "status": c.status,
                "severity": c.severity.value,
                "message": c.message,
                "tool": c.tool,
            }
            for c in report.checks
        ],
        "recommendations": report.recommendations,
    }
    return json.dumps(data, indent=2)

def _generate_recommendations(checks: list[CheckResult]) -> list[str]:
    """Generate ordered recommendations — FAILs before WARNs."""
    recs: list[tuple[int, str]] = []

    fail_checks = [c for c in checks if c.status == "FAIL"]
    warn_checks = [c for c in checks if c.status == "WARN"]

    # Deduplicate by check_id
    seen: set[str] = set()

    for check in fail_checks:
        if check.check_id in seen:
            continue
        seen.add(check.check_id)
        rec = _recommendation_for(check)
        if rec:
            recs.append((0, rec))

    for check in warn_checks:
        if check.check_id in seen:
            continue
        seen.add(check.check_id)
        rec = _recommendation_for(check)
        if rec:
            recs.append((1, rec))

    recs.sort(key=lambda x: x[0])
    return [r[1] for r in recs]

def _derive_node_name(source_file: str) -> str:
    """Derive a node name from a source file path."""
    import re
    from pathlib import Path as P

    stem = P(source_file).stem
    # Remove common suffixes
    for suffix in ("_controller", "_handler", "_router", "_routes", "_api", "_view"):
        if stem.endswith(suffix):
            stem = stem[: -len(suffix)]
            break
    return re.sub(r"[^a-z0-9_]", "_", stem.lower())

def _build_prompt(result: DiscoveryResult) -> str:
    sections = ["# System Discovery\n"]
    sections.append(
        f"Discovered {len(result.components)} components, "
        f"{len(result.models)} data models, "
        f"{len(result.routes)} API routes, "
        f"{len(result.pact_keys)} PACT keys.\n\n"
    )

    if result.components:
        sections.append("## Components\n\n")
        for c in result.components[:30]:
            sections.append(f"- **{c.name}** ({c.type.value}) — {c.source_file}:{c.line}\n")
        sections.append("\n")

    if result.routes:
        sections.append("## API Routes\n\n")
        for r in result.routes[:30]:
            sections.append(f"- `{r.method} {r.path}` — {r.framework} ({r.source_file}:{r.line})\n")
        sections.append("\n")

    if result.models:
        sections.append("## Data Models\n\n")
        for m in result.models[:30]:
            sections.append(f"- **{m.name}** ({m.orm}) — {m.source_file}:{m.line}\n")
        sections.append("\n")

    sections.append(
        "\n_This is a draft generated by Cartographer. It is not a substitute "
        "for running Constrain — it reduces the time a Constrain session takes "
        "by pre-populating discoverable facts._\n"
    )
    return "".join(sections)

def _build_component_map(result: DiscoveryResult) -> dict:
    components = []
    for c in result.components:
        components.append({
            "_draft": True,
            "_generated_by": "cartographer",
            "name": c.name.lower().replace(" ", "_"),
            "type": c.type.value,
            "source_file": c.source_file,
            "_confidence": c.confidence.value,
            "data_access": {"_note": "Must be filled during Constrain session"},
            "authority": {"_note": "Must be filled during Constrain session"},
            "dependencies": c.dependencies,
        })
    return {"_draft": True, "_generated_by": "cartographer", "components": components, "edges": []}

def _build_trust_policy(result: DiscoveryResult) -> dict:
    tiers = set()
    for sf in result.sensitive_fields:
        tiers.add(sf.classification_hint)

    return {
        "_draft": True,
        "_generated_by": "cartographer",
        "trust": {
            "floor": 0.15,
            "_note": "Minimal trust policy — all values at floor. Refine during Constrain session.",
        },
        "classifications": sorted(tiers) if tiers else ["PUBLIC"],
    }

def _build_schema_hints(result: DiscoveryResult) -> dict:
    backends = []
    for ev in result.env_vars:
        if ev.backend_hint:
            backends.append({
                "env_var": ev.name,
                "type": ev.backend_hint,
                "_confidence": ev.confidence.value,
            })

    field_hints = []
    for sf in result.sensitive_fields:
        field_hints.append({
            "field": sf.field_name,
            "classification": sf.classification_hint,
            "_confidence": sf.confidence.value,
            "_note": f"Matched pattern: {sf.pattern_matched}",
        })

    return {
        "_draft": True,
        "_generated_by": "cartographer",
        "storage_backends": backends,
        "field_hints": field_hints[:50],  # Cap to avoid oversized files
    }

def _build_schema(model: DiscoveredModel) -> dict:
    fields = []
    for field in model.fields:
        entry: dict = {
            "name": field.name,
            "type": field.type,
            "_confidence": field.confidence.value,
        }
        if field.classification_hint:
            entry["classification"] = field.classification_hint
            entry["_classification_confidence"] = "low"
            entry["_note"] = "Classification from field name pattern — human must confirm"
        if field.note:
            entry["_note"] = field.note
        fields.append(entry)

    return {
        "_draft": True,
        "_generated_by": "cartographer",
        "model_name": model.name,
        "source_file": model.source_file,
        "line": model.line,
        "orm": model.orm,
        "_confidence": model.confidence.value,
        "fields": fields,
    }

def _build_contract(component: DiscoveredComponent) -> dict:
    return {
        "_draft": True,
        "_generated_by": "cartographer",
        "component_id": _slugify(component.name),
        "name": component.name,
        "type": component.type.value,
        "source_file": component.source_file,
        "interface": {
            method: {
                "_confidence": component.confidence.value,
                "_note": "Derived from public method signature",
                "params": {},
                "returns": {},
            }
            for method in component.public_methods
        },
        "data_access": {
            "_confidence": "low",
            "_note": "Must be filled by human — cannot be inferred from source",
            "reads": [],
            "writes": [],
            "rationale": "",
        },
        "authority": {
            "_confidence": "low",
            "_note": "Must be filled by human — cannot be inferred from source",
            "domains": [],
            "rationale": "",
        },
        "dependencies": component.dependencies,
    }

def _slugify(name: str) -> str:
    import re
    # Convert CamelCase to snake_case
    s = re.sub(r"(?<!^)(?=[A-Z])", "_", name).lower()
    return re.sub(r"[^a-z0-9_]", "_", s)
